const fs = require('fs');
const yaml = require('js-yaml');
const files = [
  'src/skf-analyze-source/steps-c/step-06-generate-briefs.md',
  'src/skf-audit-skill/steps-c/step-06-report.md',
  'src/skf-create-skill/steps-c/step-08-report.md',
  'src/skf-test-skill/steps-c/step-06-report.md',
  'src/skf-create-skill/steps-c/step-05-compile.md',
  'src/skf-create-skill/steps-c/step-06-validate.md',
];
let ok = 0;
for (const f of files) {
  const content = fs.readFileSync(f, 'utf8');
  const m = content.match(/^---\n([\s\S]*?)\n---/);
  if (!m) { console.log('NO FRONTMATTER:', f); continue; }
  try {
    const parsed = yaml.load(m[1]);
    console.log('OK', f, '→ nextStepFile =', JSON.stringify(parsed.nextStepFile));
    ok++;
  } catch (e) {
    console.log('FAIL', f, e.message);
  }
}
console.log(ok + '/' + files.length, 'files parse cleanly');
"
